// === Карта выдачи: slug → способ доставки ===
// Заменить REPLACE_* на реальные значения после загрузки файлов в Google Drive
// и подготовки страниц-инструкций / Notion-копий / шаблонов Google Sheets.
//
// deliveryType:
//   'file' — n8n скачает файл из Google Drive и приложит к письму (для PDF/Excel/zip).
//   'link' — n8n отправит письмо со ссылкой, без вложения
//             (для Notion-шаблонов, Google Sheets-копий, активации Pro-доступа).
const MAP = {
  'unit-economy-excel':      { deliveryType: 'file', fileId: 'REPLACE_FILE_ID_unit_economy_excel',  fileName: 'unit-economy-excel.xlsx', title: 'Юнит-экономика SKU для WB и Ozon' },
  'wb-launch-30-days':       { deliveryType: 'file', fileId: 'REPLACE_FILE_ID_wb_launch_30_days',  fileName: 'wb-launch-30-days.pdf',   title: 'Запуск на Wildberries за 30 дней' },
  'wb-card-templates':       { deliveryType: 'file', fileId: 'REPLACE_FILE_ID_wb_card_templates',  fileName: 'wb-card-templates.zip',   title: 'Шаблоны карточек WB' },
  'self-employed-checklist': { deliveryType: 'file', fileId: 'REPLACE_FILE_ID_self_employed',      fileName: 'self-employed-checklist.pdf', title: 'Регистрация самозанятого за 1 час' },
  'raise-price-scripts':     { deliveryType: 'file', fileId: 'REPLACE_FILE_ID_raise_price',        fileName: 'raise-price-scripts.pdf', title: 'Скрипты переписки: подъём цены' },
  'contract-template':       { deliveryType: 'file', fileId: 'REPLACE_FILE_ID_contract_template', fileName: 'contract-template.zip',   title: 'Шаблон договора оказания услуг' },
  'ozon-niche-matrix':       { deliveryType: 'link', shareUrl: 'REPLACE_GOOGLE_SHEETS_COPY_URL',                            title: 'Матрица ниш Ozon — Google Sheets' },
  'notion-crm-master':       { deliveryType: 'link', shareUrl: 'REPLACE_NOTION_DUPLICATE_URL',                                title: 'CRM в Notion для мастера и фрилансера' },
  'calc-pro-year':           { deliveryType: 'link', shareUrl: 'https://artemida2.github.io/busines/pro-access/?plan=year', title: 'Калькулятор Pro — годовой доступ' },
  'calc-pro-lifetime':       { deliveryType: 'link', shareUrl: 'https://artemida2.github.io/busines/pro-access/?plan=lifetime', title: 'Калькулятор Pro — пожизненный доступ' }
};

const body = items[0].json.body || items[0].json;
const object = (body && body.object) || {};
const metadata = object.metadata || {};
const slug = (metadata.guide_slug || '').toString();
const email = (metadata.email || (object.receipt && object.receipt.customer && object.receipt.customer.email) || '').toString().trim();
const paymentId = (object.id || '').toString();
const amount = object.amount || {};

if (!slug || !MAP[slug]) {
  throw new Error('Unknown or missing guide_slug in metadata: ' + slug);
}
if (!email) {
  throw new Error('Missing email in metadata');
}

const product = MAP[slug];

return [{
  json: {
    guide_slug: slug,
    email,
    payment_id: paymentId,
    amount_value: amount.value,
    amount_currency: amount.currency,
    title: product.title,
    delivery_type: product.deliveryType,
    fileId: product.fileId || '',
    fileName: product.fileName || '',
    shareUrl: product.shareUrl || ''
  }
}];
